    "\n",
    "# -----------------------------\n",
    "# Step 3: Fill missing values\n",
    "# -----------------------------\n",
    "\n",
    "# Fill numeric columns with mean\n",
    "for col in df.select_dtypes(include=['int64', 'float64']).columns:\n",
    "    df[col] = df[col].fillna(df[col].mean())\n",
    "\n",
    "# Fill categorical columns with mode\n",
    "for col in df.select_dtypes(include=['object']).columns:\n",
    "    df[col] = df[col].fillna(df[col].mode()[0])\n",
    "\n",
    "# -----------------------------\n",
    "# Step 4: Remove duplicate rows\n",
    "# -----------------------------\n",
    "df.drop_duplicates(inplace=True)\n",
    "\n",
    "# -----------------------------\n",
    "# Step 5: Convert columns to correct data types\n",
    "# -----------------------------\n",
    "\n",
    "# Integer columns\n",
    "df['CustomerID'] = df['CustomerID'].astype(int)\n",
    "df['Age'] = df['Age'].round(0).astype(int)\n",
    "df['Cluster'] = df['Cluster'].round(0).astype(int)\n",
    "\n",
    "# Float columns → round to 2 decimals\n",
    "df['AnnualIncome'] = df['AnnualIncome'].astype(float).round(2)\n",
    "df['SpendingScore'] = df['SpendingScore'].astype(float).round(2)\n",
    "df['LoyaltyScore'] = df['LoyaltyScore'].astype(float).round(2)\n",
    "df['PurchaseFrequency'] = df['PurchaseFrequency'].astype(float).round(2)\n",
    "\n",
    "# Categorical columns\n",
    "df['Gender'] = df['Gender'].astype(str)\n",
    "df['Region'] = df['Region'].astype(str)\n",
    "df['ProductCategory'] = df['ProductCategory'].astype(str)\n",
