    "import pandas as pd\n",
    "from sklearn.preprocessing import LabelEncoder, StandardScaler\n",
    "from sklearn.cluster import KMeans\n",
    "from sklearn.ensemble import RandomForestClassifier\n",
    "from sklearn.model_selection import train_test_split\n",
    "from sklearn.metrics import classification_report, accuracy_score, silhouette_score, davies_bouldin_score\n",
    "import matplotlib.pyplot as plt\n",
    "\n",
    "# -----------------------------\n",
    "# Step 1: Load the cleaned dataset\n",
    "# -----------------------------\n",
    "df = pd.read_csv(\"filled_cleaned_data.csv\")\n",
    "\n",
    "# -----------------------------\n",
    "# Step 2: Encode categorical variables\n",
    "# -----------------------------\n",
    "le = LabelEncoder()\n",
    "df['Gender'] = le.fit_transform(df['Gender'])\n",
    "df['Region'] = le.fit_transform(df['Region'])\n",
    "df['ProductCategory'] = le.fit_transform(df['ProductCategory'])\n",
    "\n",
    "# -----------------------------\n",
    "# Step 3: Select features for segmentation\n",
    "# -----------------------------\n",
    "features = ['Gender','AnnualIncome','SpendingScore','LoyaltyScore','PurchaseFrequency','Region','ProductCategory']\n",
    "X = df[features]\n",
    "\n",
    "# -----------------------------\n",
    "# Step 4: Apply KMeans to create clusters\n",
    "# -----------------------------\n",
    "kmeans = KMeans(n_clusters=4, random_state=42)\n",
    "df['Cluster'] = kmeans.fit_predict(X)\n",
    "\n",
    "# -----------------------------\n",
    "# Step 5: Cluster Quality Evaluation\n",
    "# -----------------------------\n",
    "sil_score = silhouette_score(X, df['Cluster'])\n",
    "dbi_score = davies_bouldin_score(X, df['Cluster'])\n",
    "\n",
    "print(\"\\n🔹 Cluster Quality Metrics:\")\n",
    "print(f\"Silhouette Score: {sil_score:.4f}  (closer to 1 is better)\")\n",
    "print(f\"Davies-Bouldin Index: {dbi_score:.4f}  (lower is better)\")\n",
