    "# -----------------------------\n",
    "# Step 6: Train Random Forest on cluster labels\n",
    "# -----------------------------\n",
    "X_train, X_test, y_train, y_test = train_test_split(X, df['Cluster'], test_size=0.2, random_state=42)\n",
    "\n",
    "rf = RandomForestClassifier(n_estimators=100, random_state=42)\n",
    "rf.fit(X_train, y_train)\n",
    "\n",
    "# -----------------------------\n",
    "# Step 7: Evaluate Random Forest\n",
    "# -----------------------------\n",
    "y_pred = rf.predict(X_test)\n",
    "\n",
    "print(\"\\n🔹 Random Forest Segmentation Results:\")\n",
    "print(\"Accuracy:\", accuracy_score(y_test, y_pred))\n",
    "print(\"\\nClassification Report:\\n\", classification_report(y_test, y_pred))\n",
    "\n",
    "# -----------------------------\n",
    "# Step 8: Feature Importance\n",
    "# -----------------------------\n",
    "importances = rf.feature_importances_\n",
